PREFIX skos: <http://www.w3.org/2004/02/skos/core#>

SELECT DISTINCT ?binding_site_annotation_ligand ?binding_site_annotation_begin_position ?binding_site_annotation_end_position
WHERE {
    VALUES ?uniprot_gene_name { "ACE2" }
    VALUES ?UniProt__class { core:Protein chembl:UniprotRef }
